21	func claimLivenessPath(ddxDir, id string) string {
22		root := canonicalClaimRoot(ddxDir)
23		sum := sha1.Sum([]byte(root))
24		return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
25	}
