27	func canonicalClaimRoot(ddxDir string) string {
28		root := filepath.Clean(filepath.Dir(ddxDir))
29		if abs, err := filepath.Abs(root); err == nil {
30			root = abs
31		}
32		if real, err := filepath.EvalSymlinks(root); err == nil {
33			root = real
34		}
35		return filepath.Clean(root)
36	}
