38	func writeAtomicClaimFile(path string, data []byte) error {
39		dir := filepath.Dir(path)
40		if err := os.MkdirAll(dir, 0o755); err != nil {
41			return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
42		}
43		tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
44		if err != nil {
45			return fmt.Errorf("bead: create claim liveness tmp: %w", err)
46		}
47		tmpName := tmp.Name()
48		defer func() {
49			_ = tmp.Close()
50			_ = os.Remove(tmpName)
51		}()
52		if _, err := tmp.Write(data); err != nil {
53			return fmt.Errorf("bead: write claim liveness tmp: %w", err)
54		}
55		if err := tmp.Close(); err != nil {
56			return fmt.Errorf("bead: close claim liveness tmp: %w", err)
57		}
58		if err := os.Rename(tmpName, path); err != nil {
59			return fmt.Errorf("bead: publish claim liveness: %w", err)
60		}
61		return nil
62	}
