64	func (s *Store) TouchClaimHeartbeat(id string) error {
65		rec := claimLivenessRecord{
66			BeadID:    id,
67			UpdatedAt: time.Now().UTC(),
68			PID:       os.Getpid(),
69		}
70		data, err := json.Marshal(rec)
71		if err != nil {
72			return fmt.Errorf("bead: marshal claim liveness: %w", err)
73		}
74		data = append(data, '\n')
75		return writeAtomicClaimFile(claimLivenessPath(s.Dir, id), data)
76	}
