78	func (s *Store) RemoveClaimHeartbeat(id string) error {
79		err := os.Remove(claimLivenessPath(s.Dir, id))
80		if err == nil || os.IsNotExist(err) {
81			return nil
82		}
83		return fmt.Errorf("bead: remove claim liveness: %w", err)
84	}
