86	func (s *Store) ClaimHeartbeatFresh(id string) (bool, bool, error) {
87		data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
88		if os.IsNotExist(err) {
89			return false, false, nil
90		}
91		if err != nil {
92			return false, false, fmt.Errorf("bead: read claim liveness: %w", err)
93		}
94		var rec claimLivenessRecord
95		if err := json.Unmarshal(data, &rec); err != nil {
96			return false, true, fmt.Errorf("bead: parse claim liveness: %w", err)
97		}
98		if rec.UpdatedAt.IsZero() {
99			return false, true, nil
100		}
101		return time.Since(rec.UpdatedAt) <= HeartbeatTTL, true, nil
102	}
